 *  2022.06.09   김장하      NSR 보안조치 (removeOSCmdRisk 함수에 윈도우 다중 명령 실행 키워드 추가)
 *  2023.08.10   신용호      removeLDAPInjectionRisk() 오류 수정
 *  2024.12.04   신용호      filePathBlackList() basePath 추가
 * </pre>
 */

public class EgovWebUtil {
	public static String clearXSSMinimum(String value) {
		if (value == null || value.trim().equals("")) {
			return "";
		}

		String returnValue = value;

		returnValue = returnValue.replaceAll("&", "&amp;");
		returnValue = returnValue.replaceAll("<", "&lt;");
		returnValue = returnValue.replaceAll(">", "&gt;");
		returnValue = returnValue.replaceAll("\"", "&#34;");
		returnValue = returnValue.replaceAll("\'", "&#39;");
		returnValue = returnValue.replaceAll("\\.", "&#46;");
		returnValue = returnValue.replaceAll("%2E", "&#46;");
		returnValue = returnValue.replaceAll("%2F", "&#47;");
		return returnValue;
	}

	public static String clearXSSMaximum(String value) {
		String returnValue = value;
		returnValue = clearXSSMinimum(returnValue);

		returnValue = returnValue.replace("%00", "");

		returnValue = returnValue.replaceAll("%", "&#37;");

		// \\. => .

		returnValue = returnValue.replaceAll("\\.\\./", ""); // ../
		returnValue = returnValue.replaceAll("\\.\\.\\\\", ""); // ..\
		returnValue = returnValue.replaceAll("\\./", ""); // ./
		returnValue = returnValue.replaceAll("%2F", "");

		return returnValue;
	}

	public static String clearXSS(String value) {
		if (value == null || value.trim().equals("")) {
			return "";
		}

		String returnValue = value;
		returnValue = returnValue.replaceAll("&", "&amp;");
		returnValue = returnValue.replaceAll("%2E", "&#46;");
		returnValue = returnValue.replaceAll("%2F", "&#47;");
		returnValue = returnValue.replaceAll("<", "&lt;");
		returnValue = returnValue.replaceAll(">", "&gt;");
		returnValue = returnValue.replaceAll("%3C", "&lt;");
		returnValue = returnValue.replaceAll("%3E", "&gt;");

		return returnValue;
	}

	public static String filePathBlackList(String value) {
		String returnValue = value;
		if (returnValue == null || returnValue.trim().equals("")) {
			return "";
		}

		returnValue = returnValue.replaceAll("\\.\\.", "");

		return returnValue;
	}

	/**
	 * 파일경로 보안취약점 조치
	 * # 주의사항
	 * 1. basePath는 반드시 지정해야 한다.
	 * 2. basePath는 ROOT Path "/" 사용 금지 한다.

 * @version 1.0
 * @see <pre>
 * &lt;&lt; 개정이력(Modification Information) &gt;&gt;
 *   
 *   수정일      수정자           수정내용
 *  -------    --------    ---------------------------
 *   2009.07.03  장동한          최초 생성
 * 
 * </pre>
 */
public class RssInfo extends ComDefaultVO {

	private static final long serialVersionUID = 1L;

	/** RSS태그관리 아이디 */
	private String rssId;

	/** 서비스명 */
	private String trgetSvcNm;

	/** 서비스TABLE */
	private String trgetSvcTable;

	/** 헤더 TITLE */
	private String hderTitle;

	/** 헤더	LINK */
	private String hderLink;

	/** 헤더 DESCRIPTION */
	private String hderDescription;

	/** 헤더 TAG */
	private String hderTag;

	/** 헤더 ETC */
	private String hderEtc;

	/** 본문 TITLE */
	private String bdtTitle;

	/** 본문 LINK */
	private String bdtLink;

	/** 본문 DESCRIPTION */
	private String bdtDescription;

	/** 본문 TAG */
	private String bdtTag;

	/** 본문 ETC */
	private String bdtEtc;

    /** 최초등록시점 */
    private String frstRegisterPnttm;

    /** 최초등록아이디 */
    private String frstRegisterId;

    /** 최종수정일 */
    private String lastUpdusrPnttm;

    /** 최종수정자 아이디 */
    private String lastUpdusrId;

	/**
	 * @return the rssId
	 */
	public String getRssId() {
		return rssId;
	}

	/**
	 * @param rssId the rssId to set
	 */
	public void setRssId(String rssId) {
		this.rssId = rssId;
	}

	/**

    /**
     * RSS서비스 목록을 상세조회 조회한다.
     * @param rssInfo -RSS서비스 객체
     * @param commandMap -Request Variable
     * @param model -Spring 제공하는 ModelMap
     * @return String -리턴 URL
     * @throws Exception
     */
    @SuppressWarnings("unchecked")
	@RequestMapping(value = "/uss/ion/rsn/detailRssTagService.do")
    public String EgovRssTagServiceDetail(
            RssInfo rssInfo,
            @RequestParam Map<?, ?> commandMap,
            ModelMap model) throws Exception {

    		String sRssId = commandMap.get("rssId") == null ? "" : (String) commandMap.get("rssId");

    		if(!sRssId.equals("")){

    			Map<String, String> mapRssInfo = (Map<String, String>) egovRssService.selectRssTagServiceDetail(rssInfo);
    			model.addAttribute("mapRssInfo",mapRssInfo);

    			mapRssInfo.put("TRGET_SVC_TABLE", EgovWebUtil.removeSQLInjectionRisk(mapRssInfo.get("TRGET_SVC_TABLE")));	// 2012.11 KISA 보안조치

    			model.addAttribute("mapRssInfoList", egovRssService.selectRssTagServiceTable(mapRssInfo));

    		}

        	return "egovframework/com/uss/ion/rsn/EgovRssTagService";
    }


}
